from collections import Counter

class Solution:
    def minCost(self, nums1, nums2):
        c1 = Counter(nums1)
        c2 = Counter(nums2)
        values = set(c1) | set(c2)
        diff_sum = 0
        for v in values:
            total = c1.get(v, 0) + c2.get(v, 0)
            if total % 2 != 0:
                return -1
            diff_sum += abs(c1.get(v, 0) - c2.get(v, 0))
        return diff_sum // 4

