var minCost = function(nums1, nums2) {
    const c1 = new Map();
    const c2 = new Map();
    for (const v of nums1) c1.set(v, (c1.get(v) || 0) + 1);
    for (const v of nums2) c2.set(v, (c2.get(v) || 0) + 1);
    const values = new Set([...c1.keys(), ...c2.keys()]);
    let diffSum = 0;
    for (const v of values) {
        const a = c1.get(v) || 0;
        const b = c2.get(v) || 0;
        if ((a + b) % 2 !== 0) return -1;
        diffSum += Math.abs(a - b);
    }
    return diffSum / 4;
};
